16→"""
17→Updated chat template for Qwen2.5 Instruct models that has {% generation %} tags inserted (required by Levanter).
18→Note that all Qwen2.5-XXX-Instruct models have the same chat template.
19→
20→NOTE (moojink): One tricky/subtle thing here when modifying the chat template was this line:
21→
22→    {{- '<|im_start|>' + message.role }}{%- if message.content %}{{- '\n' }}{%- endif %}{% generation %}{%- if message.content %}{{- message.content }}{%- endif %}
23→
24→    The reason why it's structured like this is because, in the original template, the newline ('\n') is only added if the message content exists.
25→    Note that you don't want to add the newline inside the {% generation %} tags though because the model's not supposed to generate that.
26→    Therefeore, we conditionally add both the newline character and generation block, separately.
27→"""
28→
29→QWEN_2_5_INSTRUCT_CHAT_TEMPLATE = r"""{%- if tools %}
30→    {{- '<|im_start|>system\n' }}
31→    {%- if messages[0]['role'] == 'system' %}
32→        {{- messages[0]['content'] }}
33→    {%- else %}
34→        {{- 'You are Qwen, created by Alibaba Cloud. You are a helpful assistant.' }}
35→    {%- endif %}
36→    {{- "\n\n# Tools\n\nYou may call one or more functions to assist with the user query.\n\nYou are provided with function signatures within <tools></tools> XML tags:\n<tools>" }}
37→    {%- for tool in tools %}
38→        {{- "\n" }}
39→        {{- tool | tojson }}
40→    {%- endfor %}
41→    {{- "\n</tools>\n\nFor each function call, return a json object with function name and arguments within <tool_call></tool_call> XML tags:\n<tool_call>\n{\"name\": <function-name>, \"arguments\": <args-json-object>}\n</tool_call><|im_end|>\n" }}
42→{%- else %}
43→    {%- if messages[0]['role'] == 'system' %}
44→        {{- '<|im_start|>system\n' + messages[0]['content'] + '<|im_end|>\n' }}
45→    {%- else %}
46→        {{- '<|im_start|>system\nYou are Qwen, created by Alibaba Cloud. You are a helpful assistant.<|im_end|>\n' }}
47→    {%- endif %}
48→{%- endif %}
49→{%- for message in messages %}
50→    {%- if (message.role == "user") or (message.role == "system" and not loop.first) %}
51→        {{- '<|im_start|>' + message.role + '\n' + message.content + '<|im_end|>' + '\n' }}
52→    {%- elif message.role == "assistant" and not message.tool_calls %}
53→        {{- '<|im_start|>' + message.role + '\n' }}{% generation %}{{- message.content }}{{- '<|im_end|>' + '\n' }}{% endgeneration %}
54→    {%- elif message.role == "assistant" %}
55→        {{- '<|im_start|>' + message.role }}{%- if message.content %}{{- '\n' }}{%- endif %}{% generation %}{%- if message.content %}{{- message.content }}{%- endif %}
56→        {%- for tool_call in message.tool_calls %}
57→            {%- if tool_call.function is defined %}
58→                {%- set tool_call = tool_call.function %}
59→            {%- endif %}
60→            {{- '\n<tool_call>\n{"name": "' }}
61→            {{- tool_call.name }}
62→            {{- '", "arguments": ' }}
63→            {{- tool_call.arguments | tojson }}
64→            {{- '}\n</tool_call>' }}
65→        {%- endfor %}
66→        {{- '<|im_end|>\n' }}{% endgeneration %}
67→    {%- elif message.role == "tool" %}
68→        {%- if (loop.index0 == 0) or (messages[loop.index0 - 1].role != "tool") %}
69→            {{- '<|im_start|>user' }}
70→        {%- endif %}
71→        {{- '\n<tool_response>\n' }}
72→        {{- message.content }}
73→        {{- '\n</tool_response>' }}
74→        {%- if loop.last or (messages[loop.index0 + 1].role != "tool") %}
75→            {{- '<|im_end|>\n' }}
76→        {%- endif %}
77→    {%- endif %}
78→{%- endfor %}
79→{%- if add_generation_prompt %}
80→    {{- '<|im_start|>assistant\n' }}
81→{%- endif %}"""
82→

