 59→                {%- set content = content.split('</think>')[-1].lstrip('\n') %}
 60→            {%- endif %}
 61→        {%- endif %}
 62→        {%- if loop.index0 > ns.last_query_index %}
 63→            {%- if loop.last or (not loop.last and reasoning_content) %}
 64→                {{- '<|im_start|>' + message.role + '\n' }}{% generation %}{{- '<think>\n' + reasoning_content.strip('\n') + '\n</think>\n\n' + content.lstrip('\n') }}{% endgeneration %}
 65→            {%- else %}
