 70→        {%- endif %}
 71→        {%- if message.tool_calls %}
 72→            {%- for tool_call in message.tool_calls %}
 73→                {%- if (loop.first and content) or (not loop.first) %}
 74→                    {% generation %}{{- '\n' }}{% endgeneration %}
 75→                {%- endif %}
 76→                {%- if tool_call.function %}
 77→                    {%- set tool_call = tool_call.function %}
 78→                {%- endif %}
 79→                {% generation %}{{- '<tool_call>\n{"name": "' }}
 80→                {{- tool_call.name }}
