 82→                {%- if tool_call.arguments is string %}
 83→                    {{- tool_call.arguments }}
 84→                {%- else %}
 85→                    {{- tool_call.arguments | tojson }}
 86→                {%- endif %}
 87→                {{- '}\n</tool_call>' }}{% endgeneration %}
 88→            {%- endfor %}
 89→        {%- endif %}
 90→        {% generation %}{{- '<|im_end|>\n' }}{% endgeneration %}
 91→    {%- elif message.role == "tool" %}
 92→        {%- if loop.first or (messages[loop.index0 - 1].role != "tool") %}
 93→            {{- '<|im_start|>user' }}
 94→        {%- endif %}
 95→        {{- '\n<tool_response>\n' }}
 96→        {{- content }}
 97→        {{- '\n</tool_response>' }}
 98→        {%- if loop.last or (messages[loop.index0 + 1].role != "tool") %}
 99→            {{- '<|im_end|>\n' }}
100→        {%- endif %}
101→    {%- endif %}
102→{%- endfor %}
103→{%- if add_generation_prompt %}
104→    {{- '<|im_start|>assistant\n' }}
